SELECT PARAM_NO, DISTINCT_FIELD, DISTINCT_FIELD_2ND, PARAM_ITEM_NO,
       DEFAULT_VAL, PARAM_ITEM_ID, ALIAS_NAME, CPNY_ID, CPNY_NAME,
       DISTINCT_FIELD_NAME, DISTINCT_FIELD_2ND_NAME, ITEM_TYPE, ACTIVITY
FROM (
    SELECT a.*, ROWNUM AS RN
    FROM (


        ORDER BY PI.ORDER_NO
    ) a
    WHERE ROWNUM <= #{start, jdbcType=NUMERIC} + #{length, jdbcType=NUMERIC}
)
WHERE RN > #{start, jdbcType=NUMERIC}
